class Solution:
    def numberOfAlternatingGroups(self, colors, queries):
        n = len(colors)
        colors = list(colors)
        answer = []
        for q in queries:
            if q[0] == 2:
                idx, color = q[1], q[2]
                colors[idx] = color
            else:
                s = q[1]
                cnt = 0
                for i in range(n):
                    ok = True
                    for step in range(1, s):
                        a = colors[(i + step - 1) % n]
                        b = colors[(i + step) % n]
                        if a == b:
                            ok = False
                            break
                    if ok:
                        cnt += 1
                answer.append(cnt)
        return answer

