var numberOfAlternatingGroups = function(colors, queries) {
    const n = colors.length;
    colors = colors.slice();
    const brk = new Array(n);
    for (let i = 0; i < n; i++) {
        brk[i] = colors[i] === colors[(i - 1 + n) % n];
    }
    const answer = [];
    for (const q of queries) {
        if (q[0] === 2) {
            const idx = q[1], color = q[2];
            colors[idx] = color;
            brk[idx] = colors[idx] === colors[(idx - 1 + n) % n];
            const nxt = (idx + 1) % n;
            brk[nxt] = colors[nxt] === colors[(nxt - 1 + n) % n];
        } else {
            const s = q[1];
            const positions = [];
            for (let i = 0; i < n; i++) if (brk[i]) positions.push(i);
            if (positions.length === 0) {
                answer.push(n);
                continue;
            }
            let total = 0;
            const k = positions.length;
            for (let j = 0; j < k; j++) {
                const start = positions[j];
                const end = positions[(j + 1) % k];
                const length = end > start ? end - start : end - start + n;
                if (length >= s) total += length - s + 1;
            }
            answer.push(total);
        }
    }
    return answer;
};
